import{_ as e,o as a,c as r,ak as o}from"./chunks/framework.d_5_XLDx.js";const d=JSON.parse('{"title":"2026年软路由全屋翻墙指南","description":"","frontmatter":{"title":"2026年软路由全屋翻墙指南","createTime":"2025/10/13 01:42:48","permalink":"/blog/softrouter/","draft":true},"headers":[],"relativePath":"blog/ermao/文档/2025年软路由全屋翻墙指南.md","filePath":"blog/ermao/文档/2025年软路由全屋翻墙指南.md","lastUpdated":1769775157000}'),p={name:"blog/ermao/文档/2025年软路由全屋翻墙指南.md"};function i(s,t,n,l,g,_){return a(),r("div",null,[...t[0]||(t[0]=[o('<p>如果想要在家中所有设备（手机、电脑、智能电视等）都能自动翻墙，最省心的方式是<strong>购买一台软路由</strong>，然后在软路由上配置翻墙服务。这样，无论设备连接的是有线网络还是 WiFi，都能实现全屋翻墙。</p><p>但是我发现，很多人对软路由的概念比较模糊，甚至把软路由和翻墙机场搞混了。本文将详细介绍什么是软路由、软路由的优势、如何选择软路由，以及如何配置翻墙服务。</p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p><img src="https://image.ermao.net/images/blog/softrouter/image.png" alt="前言"></p><p>上面对话是一名读者给我发的邮件，询问苹果TV翻墙的相关问题。以我经验来看，配置一个软路由让家里所有设备都能翻墙，才是最省心的方案。</p><p>但是接下来的对话让我意识到，很多人对软路由的概念比较模糊，从未接触过软路由，同时也不了解软路由跟硬路由的区别。</p><p>今天就接这个机会，来聊聊软路由的相关知识。顺便也向诸位读者表示，你们发邮件咨询问题我都很乐意解答，这也是我写作的动力之一。</p><h2 id="什么是软路由" tabindex="-1">什么是软路由？ <a class="header-anchor" href="#什么是软路由" aria-label="Permalink to &quot;什么是软路由？&quot;">​</a></h2><p>软路由（Software Router）是一种基于软件实现的路由器功能的设备。它通常运行在通用硬件上，如PC、单板计算机（如Raspberry Pi）或专用软路由设备上。软路由通过安装特定的操作系统和路由软件，实现网络流量的管理和控制。</p><p>现在通常会用一台小型电脑（如Intel NUC、树莓派等）来充当软路由，安装专门的路由系统（如OpenWrt、pfSense、OPNsense等），然后通过配置这些系统来实现路由功能。这台软路由会接在家里的光猫后面（主路由模式），负责管理和分发网络流量。</p><p><img src="https://image.ermao.net/images/blog/softrouter/image-1.png" alt="r4s"></p><p>新手不用研究乱七八糟的配置，直接某宝搜索“软路由”即可，价格大概在300-800元不等。但是要注意，买之前需要咨询卖家是否能 <strong>刷入OpenWrt系统</strong> 。其他系统例如 iKuai 安装翻墙软件比较麻烦，不建议新手尝试。</p><h2 id="软路由的优势" tabindex="-1">软路由的优势 <a class="header-anchor" href="#软路由的优势" aria-label="Permalink to &quot;软路由的优势&quot;">​</a></h2><ol><li><p><strong>全屋翻墙</strong>：软路由可以让家里所有连接到网络的设备（手机、电脑、智能电视等）都能自动翻墙，无需在每个设备上单独配置翻墙软件。</p></li><li><p><strong>集中管理</strong>：通过软路由，可以集中管理网络流量，设置访问规则、限速等，提升网络使用体验。</p></li><li><p><strong>节省成本</strong>：相比购买多个翻墙设备，软路由只需一台设备即可实现全屋翻墙，节省了硬件成本。</p></li><li><p><strong>灵活性</strong>：软路由支持多种翻墙协议和服务，可以根据需求选择合适的翻墙方式。</p></li><li><p><strong>隐私保护</strong>：通过软路由翻墙，可以隐藏所有设备的真实IP地址，提升上网隐私和安全性。</p></li></ol><h2 id="软路由首次使用" tabindex="-1">软路由首次使用 <a class="header-anchor" href="#软路由首次使用" aria-label="Permalink to &quot;软路由首次使用&quot;">​</a></h2><p>实际上买完软路由之后如何配置，卖家都会有详细的说明以及远程协助。只要按照说明一步步操作，通常都能成功。</p><p>这里就简单废话一下，供大家参考。</p><p>一下内容以R5S、openwrt系统、主路由模式为例。</p><ol><li><strong>连接软路由</strong>：将软路由通过网线连接到光猫的LAN口，然后用电脑连接到软路由的WiFi或LAN口。</li></ol>',19)])])}const c=e(p,[["render",i]]);export{d as __pageData,c as default};
